import{_ as s,C as t,o as h,c as p,j as a,a as i,E as n,a3 as m}from"./chunks/framework.CVjg771q.js";const y=JSON.parse('{"title":"了凡四训·改过之法","description":"第二篇，发耻心、畏心、勇心以改过。","frontmatter":{"title":"了凡四训·改过之法","description":"第二篇，发耻心、畏心、勇心以改过。","category":"guide","aliases":["改过之法","了凡四训第二篇"],"source":["《了凡四训》"]},"headers":[],"relativePath":"lizhimingde/liaofan-sixun/chapter-02.md","filePath":"lizhimingde/liaofan-sixun/chapter-02.md","lastUpdated":1781102614000}'),c={name:"lizhimingde/liaofan-sixun/chapter-02.md"};function u(g,e,x,b,f,_){const r=t("DaoReadingPrelude"),o=t("DaoOriginalReading"),l=t("DaoLineGuide"),d=t("DaoKeywordCards");return h(),p("div",null,[e[0]||(e[0]=a("h1",{id:"了凡四训·改过之法",tabindex:"-1"},[i("了凡四训·改过之法 "),a("a",{class:"header-anchor",href:"#了凡四训·改过之法","aria-label":'Permalink to "了凡四训·改过之法"'},"​")],-1)),n(r,{title:"耻心、畏心、勇心——改过的三重发心",summary:"改过之法是了凡四训第二篇。了凡指出，改过须先发三心：耻心（不甘沦为禽兽）、畏心（天地鬼神实鉴临之）、勇心（奋然振作不迟疑）。在此基础上，从事上改、理上改、心上改，层层深入，而以治心为最上。",points:[{label:"发心",text:"耻心、畏心、勇心——三心具足，有过斯改。"},{label:"方法",text:"事上改→理上改→心上改，一层比一层彻底。"},{label:"效验",text:"改过之后自然有种种吉祥征兆，但不可执此自高。"}],hint:"这一篇讲的是实操方法，最适合照着检查自己的日常言行。"}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),n(o,{tone:"ink",density:"comfortable",defaultMode:"regular",modeSwitch:!1,paragraphs:["春秋诸大夫，见人言动，亿而谈其祸福，靡不验者，左国诸记可观也。大都吉凶之兆，萌乎心而动乎四体，其过於厚者常获福，过於薄者常近祸，俗眼多翳，谓有未定而不可测者。至诚合天，福之将至，观其善而必先知之矣。祸之将至，观其不善而必先知之矣。今欲获福而远祸，未论行善，先须改过。","但改过者，第一，要发耻心。思古之圣贤，与我同为丈夫，彼何以百世可师？我何以一身瓦裂？耽染尘情，私行不义，谓人不知，傲然无愧，将日沦於禽兽而不自知矣；世之可羞可耻者，莫大乎此。孟子曰：耻之於人大矣。以其得之则圣贤，失之则禽兽耳。此改过之要机也。","第二，要发畏心。天地在上，鬼神难欺，吾虽过在隐微，而天地鬼神，实鉴临之，重则降之百殃，轻则损其现福，吾何可以不惧？不惟此也。闲居之地，指视昭然；吾虽掩之甚密，文之甚巧，而肺肝早露，终难自欺；被人觑破，不值一文矣，乌得不懔懔？不惟是也。一息尚存，弥天之恶，犹可悔改；古人有一生作恶，临死悔悟，发一善念，遂得善终者。谓一念猛厉，足以涤百年之恶也。譬如千年幽谷，一灯才照，则千年之暗俱除；故过不论久近，惟以改为贵。但尘世无常，肉身易殒，一息不属，欲改无由矣。明则千百年担负恶名，虽孝子慈孙，不能洗涤；幽则千百劫沈沦狱报，虽圣贤佛菩萨，不能援引。乌得不畏？","第三，须发勇心。人不改过，多是因循退缩；吾须奋然振作，不用迟疑，不烦等待。小者如芒刺在肉，速与抉剔；大者如毒蛇啮指，速与斩除，无丝毫凝滞，此风雷之所以为益也。具是三心，则有过斯改，如春冰遇日，何患不消乎？然人之过，有从事上改者，有从理上改者，有从心上改者；工夫不同，效验亦异。","如前日杀生，今戒不杀；前日怒詈，今戒不怒；此就其事而改之者也。强制於外，其难百倍，且病根终在，东灭西生，非究竟廓然之道也。善改过者，未禁其事，先明其理；如过在杀生，即思曰：上帝好生，物皆恋命，杀彼养己，岂能自安？且彼之杀也，既受屠割，复入鼎镬，种种痛苦，彻入骨髓；己之养也，珍膏罗列，食过即空，疏食菜羹，尽可充腹，何必戕彼之生，损己之福哉？又思血气之属，皆含灵知，既有灵知，皆我一体；纵不能躬修至德，使之尊我亲我，岂可日戕物命，使之仇我憾我於无穷也？一思及此，将有对食痛心，不能下咽者矣。","如前日好怒，必思曰：人有不及，情所宜矜；悖理相干，於我何与？本无可怒者。又思天下无自是之豪杰，亦无尤人之学问；有不得，皆己之德未修，感未至也。吾悉以自反，则谤毁之来，皆磨炼玉成之地；我将欢然受赐，何怒之有？又闻谤而不怒，虽谗焰薰天，如举火焚空，终将自息；闻谤而怒，虽巧心力辩，如春蚕作茧，自取缠绵；怒不惟无益，且有害也。其馀种种过恶，皆当据理思之。此理既明，过将自止。","何谓从心而改？过有千端，惟心所造；吾心不动，过安从生？学者於好色，好名，好货，好怒，种种诸过，不必逐类寻求；但当一心为善，正念现前，邪念自然污染不上。如太阳当空，魍魉潜消，此精一之真传也。过由心造，亦由心改，如斩毒树，直断其根，奚必枝枝而伐，叶叶而摘哉？大抵最上治心，当下清净；才动即觉，觉之即无；苟未能然，须明理以遣之；又未能然，须随事以禁之；以上事而兼行下功，未为失策。执下而昧上，则拙矣。","顾发愿改过，明须良朋提醒，幽须鬼神证明；一心忏悔，昼夜不懈，经一七，二七，以至一月，二月，三月，必有效验。或觉心神恬旷；或觉智慧顿开；或处冗沓而触念皆通；或遇怨仇而回镇作喜；或梦吐黑物；或梦往圣先贤，提携接引；或梦飞步太虚；或梦幢幡宝盖，种种胜事，皆过消罪灭之象也。然不得执此自高，画而不进。","昔蘧伯玉当二十岁时，已觉前日之非而尽改之矣。至二十一岁，乃知前之所改，未尽也；及二十二岁，回视二十一岁，犹在梦中，岁复一岁，递递改之，行年五十，而犹知四十九年之非，古人改过之学如此。吾辈身为凡流，过恶猬集，而回思往事，常若不见其有过者，心粗而眼翳也。然人之过恶深重者，亦有效验：或心神昏塞，转头即忘；或无事而常烦恼；或见君子而赧然相沮；或闻正论而不乐；或施惠而人反怨；或夜梦颠倒，甚则妄言失志；皆作孽之相也，苟一类此，即须奋发，舍旧图新，幸勿自误。"]}),n(l,{lines:[{text:"今欲获福而远祸，未论行善，先须改过。",tone:"总纲",guide:"这一句是改过之法的定位：不是先急着行善，而是先停下来改过。如果过错继续在积累，行再多的善也像往漏桶里倒水。"},{text:"第一，要发耻心……此改过之要机也。",tone:"第一心 · 耻",guide:"耻不是羞耻感——那是内耗。了凡说的耻，是把古之圣贤和自己放在同一尺度上比：同样的资质，为什么别人百世可师，而你一身瓦裂？这个比照不是为了自我贬低，而是为了激发改变的动力。"},{text:"第二，要发畏心……乌得不畏？",tone:"第二心 · 畏",guide:"畏不是恐惧症。了凡说的畏有两个层次：明面上，天地鬼神记录着你的一切；深层里，时间不等人——一息不属，欲改无由矣。这层畏是催人行动的，不是让人瘫软的。"},{text:"第三，须发勇心……此风雷之所以为益也。",tone:"第三心 · 勇",guide:"小过如芒刺在肉，大过如毒蛇啮指——了凡用两个极端的比喻说同一件事：改过不能等。不是等心情好了再改，不是等环境合适了再改，是此刻、现在、当下。"},{text:"善改过者，未禁其事，先明其理……此理既明，过将自止。",tone:"理上改",guide:"单纯靠意志力戒杀戒怒，效果很差。了凡的方法更聪明：先想通原理。为什么不该杀生？因为万物皆含灵知，杀彼养己于心不安。为什么不该发怒？因为毁谤来临时，怒是春蚕作茧，不怒则如举火焚空终将自息。理通了，行为自然会跟着转。"},{text:"何谓从心而改？……如斩毒树，直断其根。",tone:"心上改",guide:"最上的方法是治心。心不动，过从哪来？这不是说不做事，而是说正念现前时，邪念自然污染不上——就像太阳出来，魍魉自己就散了。这个境界不容易，但至少要知道方向。"},{text:"昔蘧伯玉当二十岁时……古人改过之学如此。",tone:"榜样 · 蘧伯玉",guide:"了凡举了蘧伯玉的例子：二十岁觉得过去全错了，改完；二十一岁发现二十岁改得不彻底；二十二岁回头看二十一岁，又觉得还在梦中。一直到五十岁，还在知四十九岁之非。改过不是一次性的，而是一辈子的事。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),n(d,{items:[{term:"耻心",pinyin:["chǐ","xīn"],meaning:"不是羞耻或自贬，而是以圣贤为镜照见自身差距时产生的不甘。孟子说耻之于人大矣——有耻才能改，无耻则沦为禽兽而不自知。"},{term:"畏心",pinyin:["wèi","xīn"],meaning:"两层含义：一是天地在上，鬼神难欺的敬畏感；二是一息不属，欲改无由的时间紧迫感。两者合一，形成推动改变的压力。"},{term:"勇心",pinyin:["yǒng","xīn"],meaning:"奋然振作，不用迟疑，不烦等待——不被因循和退缩困住。小过如芒刺在肉立即剔除，大过如毒蛇啮指立即斩除。"},{term:"事上改",pinyin:["shì","shàng","gǎi"],meaning:"直接禁止行为本身：如杀生则戒杀，怒詈则戒怒。效果最浅，病根终在，容易东灭西生。"},{term:"理上改",pinyin:["lǐ","shàng","gǎi"],meaning:"在禁止行为之前先想通道理。如杀生之理——万物含灵知，杀彼养己于心不安。理通了，行为自然跟着转，不必强压。"},{term:"心上改",pinyin:["xīn","shàng","gǎi"],meaning:"最彻底的方法。过有千端，惟心所造；吾心不动，过安从生？如斩毒树直断其根，不需一枝一叶地修剪。"},{term:"蘧伯玉",pinyin:["qú","bó","yù"],meaning:"春秋时卫国大夫，以善于改过著称。二十岁知十九岁之非，五十岁仍知四十九岁之非——终其一生都在不断自省和改进。"}]}),e[3]||(e[3]=m("",16))])}const q=s(c,[["render",u]]);export{y as __pageData,q as default};
